from dataclasses import dataclass
from typing import Union, Optional


@dataclass
class ASTNode:
    """AST node for mathematical expressions"""
    type: str  # 'number', 'binop', 'unary'
    value: Optional[float] = None  # for numbers
    op: Optional[str] = None  # for operators
    left: Optional['ASTNode'] = None  # for binop
    right: Optional['ASTNode'] = None  # for binop
    operand: Optional['ASTNode'] = None  # for unary


def tokenize(expression: str) -> list:
    """Tokenize the expression string"""
    tokens = []
    i = 0
    n = len(expression)

    while i < n:
        c = expression[i]

        if c.isspace():
            i += 1
            continue

        if c in '()+-*/':
            tokens.append(c)
            i += 1
        elif c.isdigit() or c == '.':
            # Parse number
            num_str = []
            while i < n and (expression[i].isdigit() or expression[i] == '.'):
                num_str.append(expression[i])
                i += 1
            tokens.append(''.join(num_str))
        else:
            raise ValueError(f"Invalid token: '{c}'")

    return tokens


def parse_expression(tokens: list, precedence: dict) -> ASTNode:
    """Parse expression with operator precedence"""
    def parse_expression_helper(index, min_precedence):
        # Parse left operand
        left, index = parse_primary(tokens, index)

        while index < len(tokens):
            op = tokens[index]
            if op not in precedence:
                break

            op_precedence = precedence[op]
            if op_precedence < min_precedence:
                break

            index += 1
            right, index = parse_expression_helper(index, op_precedence + 1)
            left = ASTNode(type='binop', op=op, left=left, right=right)

        return left, index

    return parse_expression_helper(0, 0)[0]


def parse_primary(tokens: list, index: int) -> tuple:
    """Parse primary expressions (numbers, parenthesized expressions, unary operators)"""
    if index >= len(tokens):
        raise ValueError("Unexpected end of expression")

    token = tokens[index]

    if token == '(':
        # Parse parenthesized expression
        index += 1
        expr, index = parse_expression(tokens, {'+': 1, '-': 1, '*': 2, '/': 2})
        if index >= len(tokens) or tokens[index] != ')':
            raise ValueError("Unmatched parentheses")
        index += 1
        return expr, index

    elif token == '-':
        # Unary minus
        index += 1
        operand, index = parse_primary(tokens, index)
        return ASTNode(type='unary', op='-', operand=operand), index

    elif token == '+':
        # Unary plus (ignore)
        index += 1
        return parse_primary(tokens, index)

    elif token.replace('.', '', 1).isdigit():
        # Number
        value = float(token)
        return ASTNode(type='number', value=value), index + 1

    else:
        raise ValueError(f"Unexpected token: '{token}'")


def parse(expression: str) -> ASTNode:
    """Parse a string expression into an AST"""
    if not expression.strip():
        raise ValueError("Empty expression")

    tokens = tokenize(expression)
    if not tokens:
        raise ValueError("Empty expression")

    return parse_expression(tokens, {'+': 1, '-': 1, '*': 2, '/': 2})


def evaluate(node: ASTNode) -> float:
    """Evaluate an AST node to a numeric result"""
    if node.type == 'number':
        return node.value

    elif node.type == 'binop':
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == '+':
            return left_val + right_val
        elif node.op == '-':
            return left_val - right_val
        elif node.op == '*':
            return left_val * right_val
        elif node.op == '/':
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        else:
            raise ValueError(f"Unknown binary operator: {node.op}")

    elif node.type == 'unary':
        operand_val = evaluate(node.operand)
        if node.op == '-':
            return -operand_val
        elif node.op == '+':
            return operand_val
        else:
            raise ValueError(f"Unknown unary operator: {node.op}")

    else:
        raise ValueError(f"Unknown node type: {node.type}")
